class Solution:
    def rotate(self, m: list[list[int]]) -> None:
        n = len(m)
        # 第一步:沿主对角线转置(行列互换)
        for i in range(n):
            for j in range(i + 1, n):           # j 从 i+1 起,只换上三角,避免换回去
                m[i][j], m[j][i] = m[j][i], m[i][j]
        # 第二步:每行左右翻转。转置 + 翻转 = 顺时针旋转 90°
        for row in m:
            row.reverse()
